sql:
SELECT COUNT(*) AS total_failures, AVG(build_duration) AS average_duration
FROM build_logs
WHERE build_status = 'Failure';

SELECT build_status, COUNT(*) as build_count
FROM build_logs
GROUP BY build_status;

external_knowledge:
; Active users are those with `is_active` set to `1`; 
; Shared libraries refer to configurations where `shared` is `1` and have version updates; 
; Recently updated configurations are those with `last_modified_date` greater than or equal to '2023-10-01', which is considered the last month; 
; Version updates are considered when the count of `version_number` is greater than or equal to `2`.

sql:
SELECT library_name
FROM shared_libraries
WHERE library_id = 0;

SELECT COUNT(*) 
   FROM shared_libraries 
   WHERE created_by = 0;
